Vue.config.devtools=!1,Vue.config.debug=!1,Vue.config.silent=!0,Vue.config.ignoredElements=["app"];var app=new Vue({el:"#app",data:{source:"https://blue-heart-48ff.bigtentgames.workers.dev/",isFetching:!1,rawStats:[],stats:[],error:""},methods:{async LoadPage(){await this.GetStats(),this.stats=this.ProcessRawStats()},async GetStats(){this.isFetching=!0;try{let t=await fetch(this.source,{method:"GET",headers:{"Content-Type":"application/json"}});t.ok?(this.rawStats=await t.json(),this.isFetching=!1):(this.error="Error fetching data: "+t.statusText,this.isFetching=!1)}catch(t){this.error="Error fetching data: "+t,this.isFetching=!1}},ProcessRawStats(){let t=[];t.push({key:"Basic",value:[{key:"Total games created",value:this.rawStats.totalGames},{key:"Crazy hard games",value:this.rawStats.totalHardGames}]});let a=[];this.rawStats.languagesCount.forEach((t=>{a.push({key:AllLanguages.find((a=>a.tag===t.lang)).name+" games",value:t.count})})),a.sort(((t,a)=>a.value-t.value)),t.push({key:"Languages",value:a});let e=[];return this.rawStats.wordsetIDCount.forEach((t=>{e.push({key:WordSets.find((a=>a.id===t.id)).name+" games",value:t.count})})),e.sort(((t,a)=>a.value-t.value)),t.push({key:"Categories",value:e}),t}},mounted(){this.LoadPage()},watch:{},computed:{getLanguageCounts:function(){return[]}}});